import{_ as a,o as e,c as i,a2 as o}from"./chunks/framework.CkslIjGF.js";const k=JSON.parse('{"title":"Service Discovery","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/service-discovery.md","filePath":"concepts/service-discovery.md"}'),r={name:"concepts/service-discovery.md"};function t(n,s,l,p,c,d){return e(),i("div",null,[...s[0]||(s[0]=[o(`<h1 id="service-discovery" tabindex="-1">Service Discovery <a class="header-anchor" href="#service-discovery" aria-label="Permalink to &quot;Service Discovery&quot;">​</a></h1><h2 id="como-apps-e-resources-se-encontram" tabindex="-1">Como Apps e Resources se Encontram? <a class="header-anchor" href="#como-apps-e-resources-se-encontram" aria-label="Permalink to &quot;Como Apps e Resources se Encontram?&quot;">​</a></h2><p>O Torukr não inclui um serviço de DNS interno dedicado (como CoreDNS no Kubernetes). A descoberta de serviços é feita através do Network Overlay e da própria API do Torukr.</p><h2 id="descoberta-via-ip-do-overlay" tabindex="-1">Descoberta via IP do Overlay <a class="header-anchor" href="#descoberta-via-ip-do-overlay" aria-label="Permalink to &quot;Descoberta via IP do Overlay&quot;">​</a></h2><p>Quando apps e resources estão na mesma network overlay, eles recebem IPs fixos no range da subnet configurada. Uma app pode se conectar a um resource usando esse IP diretamente.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Descobrir IP do resource no overlay</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">torukrctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resource</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> banco-principal</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ou via API</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  http://localhost:8080/api/v1/resources/banco-principal</span></span></code></pre></div><h2 id="descoberta-via-api-do-torukr" tabindex="-1">Descoberta via API do Torukr <a class="header-anchor" href="#descoberta-via-api-do-torukr" aria-label="Permalink to &quot;Descoberta via API do Torukr&quot;">​</a></h2><p>Applications podem consultar a API do Torukr para descobrir o endereço de outros serviços:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Listar resources de um namespace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;http://localhost:8080/api/v1/resources?namespace=default&quot;</span></span></code></pre></div><h2 id="ingress-host" tabindex="-1">Ingress Host <a class="header-anchor" href="#ingress-host" aria-label="Permalink to &quot;Ingress Host&quot;">​</a></h2><p>Apps podem ter um <code>ingressHost</code> configurado, que define o hostname externo pelo qual a app é acessível:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;minha-api&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;ingressHost&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;api.meudominio.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>A configuração do ingress (proxy reverso, DNS, TLS externo) é responsabilidade do operador. O Torukr registra o <code>ingressHost</code> mas não provisiona automaticamente o ingress controller.</p></div><h2 id="comunicacao-entre-nodes" tabindex="-1">Comunicação entre Nodes <a class="header-anchor" href="#comunicacao-entre-nodes" aria-label="Permalink to &quot;Comunicação entre Nodes&quot;">​</a></h2><p>Containers em nodes diferentes se comunicam através do <a href="/concepts/network-overlay.html">Network Overlay</a> (WireGuard + VXLAN). Para que a comunicação funcione:</p><ol><li>Ambos os nodes devem estar na mesma network overlay</li><li>WireGuard deve estar configurado e com handshake estabelecido</li><li>As regras de firewall não podem bloquear o tráfego overlay</li></ol><h2 id="limitacoes-atuais" tabindex="-1">Limitações Atuais <a class="header-anchor" href="#limitacoes-atuais" aria-label="Permalink to &quot;Limitações Atuais&quot;">​</a></h2><ul><li>Não há DNS interno automático (como <code>meu-resource.default.svc.torukr</code>)</li><li>Alocação de IPs no overlay é gerenciada pelo NetworkReconciler mas a visibilidade de qual container tem qual IP requer inspeção manual</li><li>A vinculação explícita de networks a apps/resources ainda está em desenvolvimento</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/concepts/network-overlay.html">Network Overlay</a></li><li><a href="/concepts/networks.html">Conceito de Networks</a></li><li><a href="/tutorials/connect-two-nodes.html">Tutorial: Conectar Dois Nodes</a></li></ul>`,20)])])}const u=a(r,[["render",t]]);export{k as __pageData,u as default};
